proof_block:
// The previous attempt asserted post-state facts (e.g.
//   `post1_self_.proc_dom() =~= pre_self_.proc_dom().remove(proc_ptr)`)
// unconditionally in the body. Those facts come from the *antecedent* of
// the ensures implication `P ==> det_equal` — they are NOT in scope as
// hypotheses at the body level (only the `requires` and the schema
// `assume`s are). That's exactly why the asserts failed.
//
// The repair: never make a bare assertion about post1_self_ / post2_self_
// or r1 / r2. Instead encode every step as a *purely logical implication*
// whose antecedent quotes the matching ensures-clause conjunct. Each such
// implication is provable from set-/value-theoretic reasoning alone (no
// post-state hypothesis required), and the conjunction of all of them
// gives z3 the chained reasoning it needs to discharge the outer
// `P ==> det_kill_process_none_root_equal(r1, r2, post1_self_, post2_self_)`
// obligation when it eventually adds P to its context.

// --- Domain equalities (proc / container / thread) transit through pre. ---
assert(
    post1_self_.proc_dom() == pre_self_.proc_dom().remove(proc_ptr)
    && post2_self_.proc_dom() == pre_self_.proc_dom().remove(proc_ptr)
    ==> post1_self_.proc_dom() =~= post2_self_.proc_dom()
);
assert(
    post1_self_.container_dom() == pre_self_.container_dom()
    && post2_self_.container_dom() == pre_self_.container_dom()
    ==> post1_self_.container_dom() =~= post2_self_.container_dom()
);
assert(
    post1_self_.thread_dom() == pre_self_.thread_dom()
    && post2_self_.thread_dom() == pre_self_.thread_dom()
    ==> post1_self_.thread_dom() =~= post2_self_.thread_dom()
);

// --- Returned page address: if both removals from the same pre.page_closure()
// produce the same residual and both originals were members, the removed
// elements coincide. ---
assert(
    pre_self_.page_closure().contains(r1.0)
    && pre_self_.page_closure().contains(r2.0)
    && pre_self_.page_closure().remove(r1.0) =~= pre_self_.page_closure().remove(r2.0)
    ==> r1.0 == r2.0
);

// --- Lift `post.page_closure() =~= pre.page_closure().remove(r.0)` for
// both runs into a statement about the two residuals, given equal posts. ---
assert(
    post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0)
    && post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0)
    && post1_self_.page_closure() =~= post2_self_.page_closure()
    ==> pre_self_.page_closure().remove(r1.0) =~= pre_self_.page_closure().remove(r2.0)
);

// --- Returned PointsTo view: addr from ensures, init from ensures. If both
// runs agree on the address (above) and the view's addr equals the address,
// then the addr components match. ---
assert(
    r1.0 == r1.1@.addr() && r2.0 == r2.1@.addr() && r1.0 == r2.0
    ==> r1.1@.addr() == r2.1@.addr()
);
assert(
    r1.1@.is_init() && r2.1@.is_init()
    ==> r1.1@.is_init() == r2.1@.is_init()
);

// --- Parent's children sequence is determined by `remove_value(proc_ptr)`
// applied to the *same* pre-state sequence in both runs. ---
assert(
    post1_self_.get_proc(pre_self_.get_proc(proc_ptr).parent.unwrap()).children@
        =~= pre_self_.get_proc(pre_self_.get_proc(proc_ptr).parent.unwrap()).children@.remove_value(proc_ptr)
    && post2_self_.get_proc(pre_self_.get_proc(proc_ptr).parent.unwrap()).children@
        =~= pre_self_.get_proc(pre_self_.get_proc(proc_ptr).parent.unwrap()).children@.remove_value(proc_ptr)
    ==> post1_self_.get_proc(pre_self_.get_proc(proc_ptr).parent.unwrap()).children@
        =~= post2_self_.get_proc(pre_self_.get_proc(proc_ptr).parent.unwrap()).children@
);

// --- Per-proc forall on children for non-parent procs: same pre-state value
// on both sides ==> same post-state value. Re-asserted as an implication so
// the inner forall's triggers fire even outside the antecedent's scope. ---
assert(
    (forall|p_ptr: ProcPtr| #![auto]
        post1_self_.proc_dom().contains(p_ptr) && p_ptr != pre_self_.get_proc(proc_ptr).parent.unwrap()
        ==> post1_self_.get_proc(p_ptr).children == pre_self_.get_proc(p_ptr).children)
    && (forall|p_ptr: ProcPtr| #![auto]
        post2_self_.proc_dom().contains(p_ptr) && p_ptr != pre_self_.get_proc(proc_ptr).parent.unwrap()
        ==> post2_self_.get_proc(p_ptr).children == pre_self_.get_proc(p_ptr).children)
    && post1_self_.proc_dom() =~= post2_self_.proc_dom()
    ==> forall|p_ptr: ProcPtr| #![auto]
            post1_self_.proc_dom().contains(p_ptr) && p_ptr != pre_self_.get_proc(proc_ptr).parent.unwrap()
            && post2_self_.proc_dom().contains(p_ptr)
            ==> post1_self_.get_proc(p_ptr).children == post2_self_.get_proc(p_ptr).children
);

// --- Per-proc forall on uppertree_seq: same pre-state value ==> same post. ---
assert(
    (forall|p_ptr: ProcPtr| #![auto]
        post1_self_.proc_dom().contains(p_ptr)
        ==> post1_self_.get_proc(p_ptr).uppertree_seq == pre_self_.get_proc(p_ptr).uppertree_seq)
    && (forall|p_ptr: ProcPtr| #![auto]
        post2_self_.proc_dom().contains(p_ptr)
        ==> post2_self_.get_proc(p_ptr).uppertree_seq == pre_self_.get_proc(p_ptr).uppertree_seq)
    && post1_self_.proc_dom() =~= post2_self_.proc_dom()
    ==> forall|p_ptr: ProcPtr| #![auto]
            post1_self_.proc_dom().contains(p_ptr) && post2_self_.proc_dom().contains(p_ptr)
            ==> post1_self_.get_proc(p_ptr).uppertree_seq == post2_self_.get_proc(p_ptr).uppertree_seq
);

// --- Per-proc forall on subtree_set, on the uppertree path: both
// `subtree_set@` differ from pre only by removing `proc_ptr`. ---
assert(
    (forall|p_p_ptr: ProcPtr| #![trigger post1_self_.get_proc(p_p_ptr)]
        pre_self_.get_proc(proc_ptr).uppertree_seq@.contains(p_p_ptr)
        ==> post1_self_.get_proc(p_p_ptr).subtree_set@ =~=
            pre_self_.get_proc(p_p_ptr).subtree_set@.remove(proc_ptr))
    && (forall|p_p_ptr: ProcPtr| #![trigger post2_self_.get_proc(p_p_ptr)]
        pre_self_.get_proc(proc_ptr).uppertree_seq@.contains(p_p_ptr)
        ==> post2_self_.get_proc(p_p_ptr).subtree_set@ =~=
            pre_self_.get_proc(p_p_ptr).subtree_set@.remove(proc_ptr))
    ==> forall|p_p_ptr: ProcPtr|
            #![trigger post1_self_.get_proc(p_p_ptr), post2_self_.get_proc(p_p_ptr)]
            pre_self_.get_proc(proc_ptr).uppertree_seq@.contains(p_p_ptr)
            ==> post1_self_.get_proc(p_p_ptr).subtree_set@ =~=
                post2_self_.get_proc(p_p_ptr).subtree_set@
);
